import{_ as s,o as t,c as a,ag as n}from"./chunks/framework.B7K4-9EU.js";const g=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[],"relativePath":"development/testing.md","filePath":"development/testing.md","lastUpdated":1775764995000}'),i={name:"development/testing.md"};function r(o,e,l,c,p,d){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h1><p>The Saluki testing strategy consists of four main pillars:</p><ol><li>Unit Tests (Rust/cargo)</li><li>Correctness Tests (ground-truth)</li><li>Integration Tests (panoramic)</li><li>Performance Tests (SMP)</li></ol><h2 id="unit-tests" tabindex="-1">Unit Tests <a class="header-anchor" href="#unit-tests" aria-label="Permalink to &quot;Unit Tests&quot;">​</a></h2><p>These are found throughout the Rust codebase as you would expect. You can run them with <code>cargo test</code> or you can use <code>make test</code> which will run them with <code>cargo nextest</code> for more parallelization. Platform-specific unit tests should be skipped or compiled-out for platforms they are incompatible with.</p><p>CI: <code>.gitlab/test.yml</code> — runs on both Linux (amd64/arm64) and macOS (amd64/arm64).</p><h2 id="correctness-tests-ground-truth" tabindex="-1">Correctness Tests (ground-truth) <a class="header-anchor" href="#correctness-tests-ground-truth" aria-label="Permalink to &quot;Correctness Tests (ground-truth)&quot;">​</a></h2><p>These tests serve to answer the question: <em>Does ADP produce the same output as the Datadog Agent for a given workload?</em></p><p>To answer this question, a correctness test runs ADP and the Datadog Agent side-by-side in containers and compares their output for a given input. The output comparison is semantic, not a simple byte-by-byte comparison, thus heuristics are used to assert correctness.</p><p><strong>Terminology Note:</strong> Correctness tests <em><strong>are integration tests</strong></em> in the sense that they run the entire system. However, in our repo, <em>integration tests</em> refer to a specific set of smoke tests <a href="#integration-tests-panoramic">below</a>.</p><p>Correctness test cases are specified by YAML configuration files found in <code>test/correctness</code>.</p><h3 id="binaries-and-program-flow" tabindex="-1">Binaries and Program Flow <a class="header-anchor" href="#binaries-and-program-flow" aria-label="Permalink to &quot;Binaries and Program Flow&quot;">​</a></h3><p>All binaries live under <code>bin/correctness/</code>:</p><table tabindex="0"><thead><tr><th>Binary</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>ground-truth</strong></td><td>Test runner and analyzer. Orchestrates containers, collects outputs and asserts outputs.</td></tr><tr><td><strong>millstone</strong></td><td>Deterministic load generator.</td></tr><tr><td><strong>datadog-intake</strong></td><td>Mock Datadog API: receives test output</td></tr><tr><td><strong>airlock</strong></td><td>Library for running containers in isolated groups.</td></tr></tbody></table><p>Test case configs live in <code>test/correctness/</code> (e.g. <code>test/correctness/dsd-plain/config.yaml</code>).</p><h3 id="program-flow" tabindex="-1">Program Flow <a class="header-anchor" href="#program-flow" aria-label="Permalink to &quot;Program Flow&quot;">​</a></h3><p><strong>ground-truth</strong> is the entry-point for running a test. It orchestrates the containers using the airlock library (which talks to containerd via gRPC) and asserts the correctness of the output. It:</p><ul><li>reads the test configuration files</li><li>starts two sets of containers <ul><li><code>millstone</code> -&gt; ADP -&gt; <code>datadog-intake</code></li><li><code>millstone</code> -&gt; Datadog Agent -&gt; <code>datadog-intake</code></li></ul></li><li>takes the output from <code>datadog-intake</code> and asserts that ADP and Datadog Agent behavior were equivalent</li></ul><h3 id="running" tabindex="-1">Running <a class="header-anchor" href="#running" aria-label="Permalink to &quot;Running&quot;">​</a></h3><p>Build the required container images, then run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># build images (only needed once, or after changes)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-datadog-intake-image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-millstone-image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-datadog-agent-image</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># run all correctness tests</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-correctness</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># run a single test case</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-correctness-dsd-plain</span></span></code></pre></div><p>CI: <code>.gitlab/e2e.yml</code> — <code>e2e</code> stage, 10 min timeout, retry 2.</p><h2 id="integration-tests-panoramic" tabindex="-1">Integration Tests (panoramic) <a class="header-anchor" href="#integration-tests-panoramic" aria-label="Permalink to &quot;Integration Tests (panoramic)&quot;">​</a></h2><p>Integration tests run a containerized ADP instance and assert high-level invariants: process stability, expected log output, port availability, exit behavior. They catch regressions from enabling new features or settings that cause crashes or early exits. They do not test output correctness. This type of test is often known as a &quot;smoke test.&quot; For integration tests that check system output, see <a href="#correctness-tests-ground-truth">correctness tests</a> above.</p><h3 id="running-1" tabindex="-1">Running <a class="header-anchor" href="#running-1" aria-label="Permalink to &quot;Running&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-integration</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # build images + run all</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-integration-quick</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # skip image builds</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list-integration-tests</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # list available tests</span></span></code></pre></div><h3 id="test-case-config" tabindex="-1">Test Case Config <a class="header-anchor" href="#test-case-config" aria-label="Permalink to &quot;Test Case Config&quot;">​</a></h3><p>Test cases live in <code>test/integration/cases/</code> as <code>config.yaml</code> files. The runner is <strong>panoramic</strong> (<code>bin/correctness/panoramic/</code>).</p><p>Each test defines a container and a list of high-level assertions. Assertions run sequentially by default but can also be configured to run in <code>parallel</code>.</p><p>CI: <code>.gitlab/e2e.yml</code> — same file as correctness, <code>e2e</code> stage, 10 min timeout, retry 2.</p><h2 id="benchmark-tests-single-machine-performance-smp" tabindex="-1">Benchmark Tests: Single Machine Performance (SMP) <a class="header-anchor" href="#benchmark-tests-single-machine-performance-smp" aria-label="Permalink to &quot;Benchmark Tests: Single Machine Performance (SMP)&quot;">​</a></h2><p>SMP is a system that runs on internal, dedicated infrastructure to check the Agent for performance regressions. It runs experiments across multiple replicates with statistical analysis and posts reports to PRs. Maps to the <code>benchmark</code> stage in GitLab CI (<code>.gitlab/benchmark.yml</code>).</p><p>Each experiment pairs a <strong>target</strong> (ADP container) with <strong>Lading</strong> (deterministic load generator). Lading sends payloads (DogStatsD, OTLP, logs, etc.) at configured rates using seeded generators for reproducibility. SMP measures CPU, memory, throughput — not output correctness.</p><h3 id="experiments" tabindex="-1">Experiments <a class="header-anchor" href="#experiments" aria-label="Permalink to &quot;Experiments&quot;">​</a></h3><p>Defined in <code>test/smp/regression/adp/experiments.yaml</code>. Run <code>make generate-smp-experiments</code> to generate per-case configs in <code>test/smp/regression/adp/cases/</code>. Each case gets an <code>experiment.yaml</code> (target config) and <code>lading/lading.yaml</code> (load config).</p><p>CI compares current branch against merge-base of main — purely &quot;has your change regressed or improved?&quot;</p><p>You can run experiments locally with <code>smp local-run</code> to debug experiment configs without waiting for CI (single replicate, no statistical analysis). This is mainly useful when iterating on a new or broken experiment — for normal development, lean on CI.</p><h2 id="fuzzing" tabindex="-1">Fuzzing <a class="header-anchor" href="#fuzzing" aria-label="Permalink to &quot;Fuzzing&quot;">​</a></h2><p>A fifth type of testing is fuzzing. We aren&#39;t doing a lot with fuzzing right now, but what we have uses <code>cargo-fuzz</code> and operates at the function-level. More fuzzing coverage will likely come in the future.</p><h2 id="directory-index" tabindex="-1">Directory Index <a class="header-anchor" href="#directory-index" aria-label="Permalink to &quot;Directory Index&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.gitlab/</span></span>
<span class="line"><span>├── test.yml               unit tests</span></span>
<span class="line"><span>├── e2e.yml                correctness + integration</span></span>
<span class="line"><span>├── benchmark.yml          SMP benchmarks</span></span>
<span class="line"><span>└── fuzz.yml               fuzz testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span># custom test tooling</span></span>
<span class="line"><span>bin/correctness/</span></span>
<span class="line"><span>├── ground-truth/          : test orchestrator</span></span>
<span class="line"><span>├── millstone/             : load generator</span></span>
<span class="line"><span>├── datadog-intake/        : mock Datadog API</span></span>
<span class="line"><span>├── panoramic/             : integration test runner</span></span>
<span class="line"><span>├── airlock/               : container isolation lib</span></span>
<span class="line"><span>└── stele/                 : telemetry data types</span></span>
<span class="line"><span></span></span>
<span class="line"><span># actual test cases</span></span>
<span class="line"><span>test/</span></span>
<span class="line"><span>├── correctness/           : correctness test configs</span></span>
<span class="line"><span>├── integration/           : integration test configs</span></span>
<span class="line"><span>└── smp/                   : smp experiments</span></span></code></pre></div>`,41)])])}const u=s(i,[["render",r]]);export{g as __pageData,u as default};
